SELECT OrdiniCLienteItem.Article, OrdiniCLienteItem.ColorCode, OrdiniCLienteItem.Taglia AS [Size], OrdiniCLienteItem.Description, OrdiniCLienteItem.[Description 2], OrdiniCLienteItem.[Product Sex] AS Gender, OrdiniCLienteItem.[Trademark Code], OrdiniCLienteItem.[Season Code], OrdiniCLienteItem.color, OrdiniCLienteItem.[Upper Composition], OrdiniCLienteItem.[Country_Region of Origin Code], OrdiniCLienteItem.[Outsole Composition], OrdiniCLienteItem.[Lining Composition], OrdiniCLienteItem.[Insole Composition], Sum(OrdiniCLienteItem.NetWeightTotal) AS NetWeightTotal, Sum(OrdiniCLienteItem.GrossWeightTotal) AS GrossWeightTotal, Sum(OrdiniCLienteItem.QuantitySold) AS QuantitySold, OrdiniCLienteItem.[Tariff No_], OrdiniCLienteItem.EAN, OrdiniCLienteItem.UPCCode
FROM OrdiniCLienteItem
WHERE (((OrdiniCLienteItem.[Advertising Material])=0))
GROUP BY OrdiniCLienteItem.Article, OrdiniCLienteItem.ColorCode, OrdiniCLienteItem.Taglia, OrdiniCLienteItem.Description, OrdiniCLienteItem.[Description 2], OrdiniCLienteItem.[Product Sex], OrdiniCLienteItem.[Trademark Code], OrdiniCLienteItem.[Season Code], OrdiniCLienteItem.color, OrdiniCLienteItem.[Upper Composition], OrdiniCLienteItem.[Country_Region of Origin Code], OrdiniCLienteItem.[Outsole Composition], OrdiniCLienteItem.[Lining Composition], OrdiniCLienteItem.[Insole Composition], OrdiniCLienteItem.[Tariff No_], OrdiniCLienteItem.EAN, OrdiniCLienteItem.UPCCode;

